namespace RecipeHub.Models;

public class Recipe
{
    public int Id { get; set; }
    public string Title { get; set; } = string.Empty;
    public string Category { get; set; } = string.Empty;
    public string Description { get; set; } = string.Empty;
    public List<string> Ingredients { get; set; } = [];
    public List<string> Steps { get; set; } = [];
    public int TotalRatings { get; set; }
    public int RatingSum { get; set; }
    public double AverageRating => TotalRatings > 0 ? (double)RatingSum / TotalRatings : 0;
}

using RecipeHub.Models;

namespace RecipeHub.Services;

public class RecipeService
{
    private readonly List<Recipe> _recipes;
    private int _nextId;

    public RecipeService()
    {
        _recipes =
        [
            new()
            {
                Id = 1, Title = "Classic Margherita Pizza", Category = "Italian",
                Description = "A simple and delicious pizza with fresh mozzarella, tomatoes, and basil.",
                Ingredients = ["Pizza dough", "San Marzano tomatoes", "Fresh mozzarella", "Fresh basil", "Olive oil", "Salt"],
                Steps = ["Preheat oven to 475°F.", "Roll out dough on a floured surface.", "Spread crushed tomatoes over dough.", "Tear mozzarella and distribute evenly.", "Bake for 10-12 minutes until crust is golden.", "Top with fresh basil and a drizzle of olive oil."],
                TotalRatings = 12, RatingSum = 52
            },
            new()
            {
                Id = 2, Title = "Spaghetti Carbonara", Category = "Italian",
                Description = "Creamy pasta with pancetta, eggs, and Parmesan cheese.",
                Ingredients = ["Spaghetti", "Pancetta", "Eggs", "Parmesan cheese", "Black pepper", "Salt"],
                Steps = ["Cook spaghetti in salted boiling water until al dente.", "Fry pancetta until crispy.", "Whisk eggs with grated Parmesan and pepper.", "Drain pasta, reserving some water.", "Toss hot pasta with pancetta, then quickly stir in egg mixture.", "Serve immediately with extra Parmesan."],
                TotalRatings = 8, RatingSum = 38
            },
            new()
            {
                Id = 3, Title = "Chicken Tikka Masala", Category = "Indian",
                Description = "Tender chicken in a rich, spiced tomato-cream sauce.",
                Ingredients = ["Chicken breast", "Yogurt", "Garam masala", "Tomato sauce", "Heavy cream", "Onion", "Garlic", "Ginger", "Rice"],
                Steps = ["Marinate chicken in yogurt and spices for 1 hour.", "Grill or broil chicken until charred.", "Sauté onion, garlic, and ginger.", "Add tomato sauce and simmer 15 minutes.", "Stir in cream and cooked chicken.", "Serve over basmati rice."],
                TotalRatings = 15, RatingSum = 70
            },
            new()
            {
                Id = 4, Title = "Vegetable Pad Thai", Category = "Asian",
                Description = "Stir-fried rice noodles with vegetables, peanuts, and tangy sauce.",
                Ingredients = ["Rice noodles", "Tofu", "Bean sprouts", "Carrots", "Green onions", "Peanuts", "Pad Thai sauce", "Lime", "Eggs"],
                Steps = ["Soak rice noodles in warm water for 20 minutes.", "Press and cube tofu, then pan-fry until golden.", "Scramble eggs in the same pan.", "Add vegetables and stir-fry 2 minutes.", "Add drained noodles and sauce, toss to combine.", "Top with crushed peanuts and lime wedges."],
                TotalRatings = 6, RatingSum = 26
            },
            new()
            {
                Id = 5, Title = "Beef Tacos", Category = "Mexican",
                Description = "Seasoned ground beef in crispy taco shells with fresh toppings.",
                Ingredients = ["Ground beef", "Taco seasoning", "Taco shells", "Lettuce", "Tomato", "Cheddar cheese", "Sour cream", "Salsa"],
                Steps = ["Brown ground beef in a skillet.", "Add taco seasoning and water, simmer 5 minutes.", "Warm taco shells in oven.", "Fill shells with seasoned beef.", "Top with lettuce, tomato, cheese, sour cream, and salsa.", "Serve immediately."],
                TotalRatings = 10, RatingSum = 42
            },
            new()
            {
                Id = 6, Title = "Guacamole", Category = "Mexican",
                Description = "Fresh and creamy avocado dip with lime and cilantro.",
                Ingredients = ["Avocados", "Lime juice", "Cilantro", "Red onion", "Jalapeño", "Tomato", "Salt"],
                Steps = ["Halve and pit avocados, scoop into a bowl.", "Mash to desired consistency.", "Stir in lime juice, diced onion, jalapeño, and tomato.", "Add chopped cilantro and salt to taste.", "Serve with tortilla chips."],
                TotalRatings = 9, RatingSum = 41
            },
            new()
            {
                Id = 7, Title = "Miso Ramen", Category = "Asian",
                Description = "Rich miso broth with noodles, soft-boiled egg, and toppings.",
                Ingredients = ["Ramen noodles", "Miso paste", "Chicken broth", "Soy sauce", "Sesame oil", "Soft-boiled eggs", "Green onions", "Nori", "Corn"],
                Steps = ["Bring chicken broth to a simmer.", "Whisk in miso paste, soy sauce, and sesame oil.", "Cook ramen noodles according to package.", "Divide noodles among bowls, ladle broth over.", "Top with halved soft-boiled eggs, green onions, nori, and corn.", "Serve hot."],
                TotalRatings = 11, RatingSum = 49
            },
            new()
            {
                Id = 8, Title = "Chocolate Lava Cake", Category = "Desserts",
                Description = "Individual cakes with a molten chocolate center.",
                Ingredients = ["Dark chocolate", "Butter", "Eggs", "Sugar", "Flour", "Vanilla extract"],
                Steps = ["Preheat oven to 425°F and grease ramekins.", "Melt chocolate and butter together.", "Whisk in eggs, sugar, and vanilla.", "Fold in flour gently.", "Pour into ramekins and bake 12-14 minutes.", "Invert onto plates and serve immediately."],
                TotalRatings = 14, RatingSum = 66
            },
            new()
            {
                Id = 9, Title = "Dal Tadka", Category = "Indian",
                Description = "Comfort lentil dish tempered with cumin, garlic, and ghee.",
                Ingredients = ["Yellow lentils", "Onion", "Tomato", "Garlic", "Cumin seeds", "Turmeric", "Ghee", "Cilantro"],
                Steps = ["Wash and boil lentils with turmeric until soft.", "Heat ghee and add cumin seeds until they splutter.", "Add chopped garlic and onion, sauté until golden.", "Add chopped tomatoes and cook down.", "Pour tempering over cooked lentils and stir.", "Garnish with cilantro and serve with rice."],
                TotalRatings = 7, RatingSum = 31
            },
            new()
            {
                Id = 10, Title = "Tiramisu", Category = "Desserts",
                Description = "Classic Italian layered dessert with coffee-soaked ladyfingers and mascarpone.",
                Ingredients = ["Ladyfingers", "Espresso", "Mascarpone cheese", "Eggs", "Sugar", "Cocoa powder", "Marsala wine"],
                Steps = ["Brew espresso and let it cool; mix with Marsala.", "Separate eggs; whisk yolks with sugar until thick.", "Fold mascarpone into yolk mixture.", "Beat egg whites to stiff peaks and fold in.", "Dip ladyfingers in espresso and layer in a dish.", "Spread mascarpone mixture over, repeat layers, dust with cocoa. Refrigerate 4 hours."],
                TotalRatings = 13, RatingSum = 61
            }
        ];
        _nextId = 11;
    }

    public IReadOnlyList<string> GetCategories() =>
        _recipes.Select(r => r.Category).Distinct().Order().ToList();

    public IReadOnlyList<Recipe> GetByCategory(string category) =>
        _recipes.Where(r => r.Category.Equals(category, StringComparison.OrdinalIgnoreCase)).ToList();

    public Recipe? GetById(int id) =>
        _recipes.FirstOrDefault(r => r.Id == id);

    public void AddRating(int recipeId, int stars)
    {
        var recipe = GetById(recipeId);
        if (recipe is not null && stars is >= 1 and <= 5)
        {
            recipe.TotalRatings++;
            recipe.RatingSum += stars;
        }
    }

    public void AddRecipe(string title, string category, string ingredients, string steps)
    {
        _recipes.Add(new Recipe
        {
            Id = _nextId++,
            Title = title.Trim(),
            Category = category.Trim(),
            Description = $"A community-submitted {category.Trim().ToLowerInvariant()} recipe.",
            Ingredients = ingredients.Split('\n', StringSplitOptions.RemoveEmptyEntries | StringSplitOptions.TrimEntries).ToList(),
            Steps = steps.Split('\n', StringSplitOptions.RemoveEmptyEntries | StringSplitOptions.TrimEntries).ToList()
        });
    }
}

