arguments.file_text:
@page "/category/{CategoryName}"
@inject RecipeHub.Services.RecipeService RecipeService

<PageTitle>@CategoryName Recipes — RecipeHub</PageTitle>

<nav aria-label="breadcrumb">
    <ol class="breadcrumb">
        <li class="breadcrumb-item"><a href="/">Home</a></li>
        <li class="breadcrumb-item active">@CategoryName</li>
    </ol>
</nav>

<h1>@CategoryName Recipes</h1>

@if (Recipes.Count == 0)
{
    <div class="alert alert-info">No recipes found in this category.</div>
}
else
{
    <div class="row row-cols-1 row-cols-md-2 g-4 mt-2">
        @foreach (var recipe in Recipes)
        {
            <div class="col">
                <div class="card h-100 shadow-sm">
                    <div class="card-body">
                        <h5 class="card-title">@recipe.Title</h5>
                        <p class="card-text text-muted">@recipe.Description</p>
                        <div class="d-flex justify-content-between align-items-center">
                            <span class="text-warning">
                                @for (int i = 1; i <= 5; i++)
                                {
                                    @(i <= (int)Math.Round(recipe.AverageRating) ? "★" : "☆")
                                }
                                <small class="text-muted">(@recipe.TotalRatings)</small>
                            </span>
                            <a href="/recipe/@recipe.Id" class="btn btn-sm btn-outline-primary">View Recipe</a>
                        </div>
                    </div>
                </div>
            </div>
        }
    </div>
}

@code {
    [Parameter]
    public string CategoryName { get; set; } = string.Empty;

    private IReadOnlyList<RecipeHub.Models.Recipe> Recipes { get; set; } = [];

    protected override void OnParametersSet()
    {
        Recipes = RecipeService.GetByCategory(CategoryName);
    }
}

@page "/recipe/{RecipeId:int}"
@inject RecipeHub.Services.RecipeService RecipeService

<PageTitle>@(Recipe?.Title ?? "Recipe") — RecipeHub</PageTitle>

@if (Recipe is null)
{
    <div class="alert alert-warning">Recipe not found.</div>
}
else
{
    <nav aria-label="breadcrumb">
        <ol class="breadcrumb">
            <li class="breadcrumb-item"><a href="/">Home</a></li>
            <li class="breadcrumb-item"><a href="/category/@Recipe.Category">@Recipe.Category</a></li>
            <li class="breadcrumb-item active">@Recipe.Title</li>
        </ol>
    </nav>

    <h1>@Recipe.Title</h1>
    <p class="lead text-muted">@Recipe.Description</p>

    <StarRating RecipeId="Recipe.Id" @rendermode="InteractiveServer" />

    <div class="row mt-4">
        <div class="col-md-4">
            <div class="card">
                <div class="card-header"><h5 class="mb-0">🥘 Ingredients</h5></div>
                <ul class="list-group list-group-flush">
                    @foreach (var ingredient in Recipe.Ingredients)
                    {
                        <li class="list-group-item">@ingredient</li>
                    }
                </ul>
            </div>
        </div>
        <div class="col-md-8">
            <h3>📋 Steps</h3>
            <ol class="list-group list-group-numbered mt-2">
                @foreach (var step in Recipe.Steps)
                {
                    <li class="list-group-item">@step</li>
                }
            </ol>
        </div>
    </div>
}

@code {
    [Parameter]
    public int RecipeId { get; set; }

    private RecipeHub.Models.Recipe? Recipe { get; set; }

    protected override void OnParametersSet()
    {
        Recipe = RecipeService.GetById(RecipeId);
    }
}

@rendermode InteractiveServer
@inject RecipeHub.Services.RecipeService RecipeService

<div class="my-3 p-3 border rounded bg-light">
    <h5 class="mb-2">Rate this recipe</h5>
    <div class="d-flex align-items-center gap-3">
        <span style="font-size: 1.8rem; cursor: pointer; user-select: none;">
            @for (int i = 1; i <= 5; i++)
            {
                var star = i;
                <span @onmouseover="() => hoverRating = star"
                      @onmouseout="() => hoverRating = 0"
                      @onclick="() => SubmitRating(star)"
                      class="@(i <= DisplayRating ? "text-warning" : "text-secondary")">★</span>
            }
        </span>

