toolArgs.file_text:
@page "/submit"
@rendermode InteractiveServer
@inject RecipeHub.Services.RecipeService RecipeService
@inject NavigationManager Navigation

<PageTitle>Submit a Recipe — RecipeHub</PageTitle>

<nav aria-label="breadcrumb">
    <ol class="breadcrumb">
        <li class="breadcrumb-item"><a href="/">Home</a></li>
        <li class="breadcrumb-item active">Submit Recipe</li>
    </ol>
</nav>

<h1>📝 Submit a Recipe</h1>
<p class="text-muted">Share your favorite recipe with the community.</p>

<EditForm Model="Model" OnValidSubmit="HandleSubmit" FormName="submit-recipe" class="mt-3">
    <DataAnnotationsValidator />
    <ValidationSummary class="text-danger" />

    <div class="mb-3">
        <label for="title" class="form-label">Recipe Title</label>
        <InputText id="title" @bind-Value="Model.Title" class="form-control" placeholder="e.g. Grandma's Apple Pie" />
        <ValidationMessage For="() => Model.Title" class="text-danger" />
    </div>

    <div class="mb-3">
        <label for="category" class="form-label">Category</label>
        <InputSelect id="category" @bind-Value="Model.Category" class="form-select">
            <option value="">-- Select a category --</option>
            <option value="Italian">Italian</option>
            <option value="Indian">Indian</option>
            <option value="Asian">Asian</option>
            <option value="Mexican">Mexican</option>
            <option value="Desserts">Desserts</option>
            <option value="Other">Other</option>
        </InputSelect>
        <ValidationMessage For="() => Model.Category" class="text-danger" />
    </div>

    <div class="mb-3">
        <label for="ingredients" class="form-label">Ingredients</label>
        <InputTextArea id="ingredients" @bind-Value="Model.Ingredients" class="form-control" rows="5"
                       placeholder="One ingredient per line" />
        <ValidationMessage For="() => Model.Ingredients" class="text-danger" />
    </div>

    <div class="mb-3">
        <label for="steps" class="form-label">Steps</label>
        <InputTextArea id="steps" @bind-Value="Model.Steps" class="form-control" rows="5"
                       placeholder="One step per line" />
        <ValidationMessage For="() => Model.Steps" class="text-danger" />
    </div>

    <button type="submit" class="btn btn-success">Submit Recipe</button>
</EditForm>

@if (SubmittedRecipeId.HasValue)
{
    <div class="alert alert-success mt-3">
        Recipe submitted! <a href="/recipe/@SubmittedRecipeId">View it here</a>.
    </div>
}

@code {
    private RecipeFormModel Model { get; set; } = new();
    private int? SubmittedRecipeId { get; set; }

    private void HandleSubmit()
    {
        RecipeService.AddRecipe(Model.Title, Model.Category, Model.Ingredients, Model.Steps);
        var allRecipes = RecipeService.GetByCategory(Model.Category);
        SubmittedRecipeId = allRecipes[^1].Id;
        Model = new();
    }

    private sealed class RecipeFormModel
    {
        [System.ComponentModel.DataAnnotations.Required(ErrorMessage = "Title is required.")]
        [System.ComponentModel.DataAnnotations.StringLength(100, MinimumLength = 3, ErrorMessage = "Title must be 3-100 characters.")]
        public string Title { get; set; } = string.Empty;

        [System.ComponentModel.DataAnnotations.Required(ErrorMessage = "Please select a category.")]
        public string Category { get; set; } = string.Empty;

        [System.ComponentModel.DataAnnotations.Required(ErrorMessage = "Add at least one ingredient.")]
        public string Ingredients { get; set; } = string.Empty;

        [System.ComponentModel.DataAnnotations.Required(ErrorMessage = "Add at least one step.")]
        public string Steps { get; set; } = string.Empty;
    }
}
